  1→// TM Robot 패킷 빌드 및 파싱
  2→
  3→export interface TmsctResponse {
  4→  header: string;
  5→  id: string;
  6→  status: string; // "OK" | "ERROR" 등
  7→  message: string;
  8→  raw: string;
  9→}
 10→
 11→export interface TmsvrResponse {
 12→  header: string;
 13→  mode: string;
 14→  id: string;
 15→  data: string;
 16→  raw: string;
 17→}
 18→
 19→/**
 20→ * XOR 체크섬 계산
 21→ * $ 와 * 사이의 문자열에 대해 XOR 후 2자리 HEX 반환
 22→ */
 23→function calcChecksum(content: string): string {
 24→  let xor = 0;
 25→  for (let i = 0; i < content.length; i++) {
 26→    xor ^= content.charCodeAt(i);
 27→  }
 28→  return xor.toString(16).toUpperCase().padStart(2, '0');
 29→}
 30→
 31→/**
 32→ * TMSCT 패킷 빌드
 33→ * 형식: $TMSCT,<length>,<id>,<script>,*<checksum>\r\n
 34→ */
 35→export function buildTmsctPacket(id: string, script: string): string {
 36→  // 형식: $TMSCT,<length>,<id>,<script>,*<checksum>\r\n
 37→  // length = id + ',' + script 의 바이트 수 (마지막 쉼표 미포함)
 38→  const data = `${id},${script}`;
 39→  const length = Buffer.byteLength(data, 'ascii');
 40→  const body = `TMSCT,${length},${data},`;
 41→  const checksum = calcChecksum(body);
 42→  return `$${body}*${checksum}\r\n`;
 43→}
 44→
 45→/**
 46→ * TMSVR 패킷 빌드
 47→ * 형식: $TMSVR,<length>,<mode>,<id>,<data>,*<checksum>\r\n
 48→ * mode: 0=binary, 1=JSON, 2=string
 49→ */
 50→export function buildTmsvrPacket(mode: number, id: string, data: string): string {
 51→  const innerContent = `${mode},${id},${data},`;
 52→  const length = Buffer.byteLength(innerContent, 'ascii');
 53→  const content = `TMSVR,${length},${innerContent}`;
 54→  const checksum = calcChecksum(content);
 55→  return `$${content}*${checksum}\r\n`;
 56→}
 57→
 58→/**
 59→ * TMSCT 응답 파싱
 60→ * 응답 형식: $TMSCT,<length>,<id>,<status>,*<checksum>\r\n
 61→ * 또는: $TMSCT,<length>,<id>,<status>,<message>,*<checksum>\r\n
 62→ */
 63→export function parseTmsctResponse(raw: string): TmsctResponse {
 64→  // $ 와 * 사이 추출
 65→  const match = raw.match(/\$(.+)\*([0-9A-Fa-f]{2})/);
 66→  if (!match) {
 67→    return { header: 'TMSCT', id: '', status: 'PARSE_ERROR', message: raw, raw };
 68→  }
 69→
 70→  const parts = match[1].split(',');
 71→  // parts[0] = TMSCT, parts[1] = length, parts[2] = id, parts[3..] = 나머지
 72→  return {
 73→    header: parts[0] || 'TMSCT',
 74→    id: parts[2] || '',
 75→    status: parts[3] || '',
 76→    message: parts.slice(4).join(',').replace(/[\r\n]+$/, ''),
 77→    raw,
 78→  };
 79→}
 80→
 81→/**
 82→ * TMSVR 응답 파싱
 83→ * 응답 형식: $TMSVR,<length>,<mode>,<id>,<data>,*<checksum>\r\n
 84→ */
 85→export function parseTmsvrResponse(raw: string): TmsvrResponse {
 86→  const match = raw.match(/\$(.+)\*([0-9A-Fa-f]{2})/);
 87→  if (!match) {
 88→    return { header: 'TMSVR', mode: '', id: '', data: raw, raw };
 89→  }
 90→
 91→  const parts = match[1].split(',');
 92→  return {
 93→    header: parts[0] || 'TMSVR',
 94→    mode: parts[2] || '',
 95→    id: parts[3] || '',
 96→    data: parts.slice(4).join(',').replace(/[\r\n]+$/, ''),
 97→    raw,
 98→  };
 99→}
100→
101→/**
102→ * CPERR 응답인지 확인
103→ */
104→export function isCperrResponse(raw: string): boolean {
105→  return raw.includes('$CPERR');
106→}
