 10→/// 포트 5891로 접속하여 관절 각도 및 TCP 좌표를 수신.
 11→/// </summary>
 12→public class TmRobotClient : IDisposable
 13→{
 14→    private TcpClient? _tcp;
 15→    private NetworkStream? _stream;
 16→    private CancellationTokenSource? _cts;
 17→    private Task? _receiveTask;
 18→    private readonly StringBuilder _recvBuffer = new();
 19→    private readonly string _rawLogPath = Path.Combine(AppDomain.CurrentDomain.BaseDirectory, "raw_recv.log");
 20→    private const long RAW_LOG_MAX_BYTES = 10 * 1024 * 1024; // 10MB 제한
 21→
 22→    // TMSCT 비상정지용
 23→    private int _sctCmdId;
 24→
 25→    private bool _isConnected;
 26→
 27→    public string Host { get; set; } = "192.168.1.50";
 28→    public int Port { get; set; } = 5891;
 29→    public bool IsConnected => _isConnected;
 30→
 31→    /// <summary>
 32→    /// 관절 각도(J1~J6, 도) + TCP 좌표(X,Y,Z,Rx,Ry,Rz) 수신 이벤트
 33→    /// </summary>
 34→    public event Action<double[], double[]>? DataReceived;
 35→
 36→    /// <summary>
 37→    /// 연결 상태 변경 이벤트
 38→    /// </summary>
 39→    public event Action<bool, string>? ConnectionChanged;
 40→
 41→    /// <summary>
 42→    /// 로그 이벤트
 43→    /// </summary>
 44→    public event Action<string>? LogMessage;
 45→
 46→    /// <summary>
 47→    /// 로봇에 연결
 48→    /// </summary>
 49→    public async Task ConnectAsync()
 50→    {
 51→        try
 52→        {
 53→            Disconnect();
 54→
 55→            _tcp = new TcpClient();
 56→            _tcp.ReceiveTimeout = 5000;
 57→            _tcp.SendTimeout = 5000;
 58→
 59→            LogMessage?.Invoke($"연결 시도: {Host}:{Port}");
 60→            await _tcp.ConnectAsync(Host, Port);
 61→
 62→            _stream = _tcp.GetStream();
 63→            _recvBuffer.Clear();
 64→            _isConnected = true;
 65→
 66→            LogMessage?.Invoke($"연결 성공: {Host}:{Port}");
 67→            ConnectionChanged?.Invoke(true, $"{Host}:{Port}");
 68→
 69→            // 수신 루프 시작
 70→            _cts = new CancellationTokenSource();
 71→            _receiveTask = Task.Run(() => ReceiveLoop(_cts.Token));
 72→        }
 73→        catch (Exception ex)
 74→        {
 75→            LogMessage?.Invoke($"연결 실패: {ex.Message}");
 76→            // 리소스만 정리, Disconnect 내부 이벤트 중복 방지
 77→            CleanupResources();
 78→            ConnectionChanged?.Invoke(false, ex.Message);
 79→        }
 80→    }
 81→
 82→    /// <summary>
 83→    /// 연결 해제
 84→    /// </summary>
 85→    public void Disconnect()
 86→    {
 87→        var wasConnected = _isConnected;
 88→        CleanupResources();
 89→        if (wasConnected)
 90→            ConnectionChanged?.Invoke(false, "연결 해제");
 91→    }
 92→
 93→    /// <summary>
 94→    /// TCP 리소스 정리 (이벤트 발사 없음)
 95→    /// </summary>
 96→    private void CleanupResources()
 97→    {
 98→        _isConnected = false;
 99→        try
100→        {
101→            _cts?.Cancel();
102→            _stream?.Close();
103→            _tcp?.Close();
104→        }
105→        catch { }
106→        finally
107→        {
108→            _stream = null;
109→            _tcp = null;
110→            _cts = null;
111→            _receiveTask = null;
112→            _recvBuffer.Clear();
113→        }
114→    }
115→
116→    /// <summary>
117→    /// 비동기 수신 루프
118→    /// </summary>
119→    private async Task ReceiveLoop(CancellationToken token)
120→    {
121→        var buffer = new byte[4096];
122→
123→        try
124→        {
125→            while (!token.IsCancellationRequested && _stream != null)
126→            {
127→                int bytesRead = await _stream.ReadAsync(buffer, 0, buffer.Length, token);
128→                if (bytesRead == 0)
129→                {
130→                    LogMessage?.Invoke("서버가 연결을 종료했습니다.");
131→                    break;
132→                }
133→
134→                var received = Encoding.ASCII.GetString(buffer, 0, bytesRead);
135→                try
136→                {
137→                    // 로그 크기 제한: 10MB 초과 시 삭제 후 재시작
138→                    if (File.Exists(_rawLogPath) && new FileInfo(_rawLogPath).Length > RAW_LOG_MAX_BYTES)
139→                        File.Delete(_rawLogPath);
140→                    File.AppendAllText(_rawLogPath, $"[{DateTime.Now:HH:mm:ss.fff}] {received}\n---\n");
141→                }
142→                catch { }
143→                _recvBuffer.Append(received);
144→
145→                // 완성된 패킷 처리
146→                ProcessBuffer();
147→            }
148→        }
149→        catch (OperationCanceledException) { }
150→        catch (Exception ex)
151→        {
152→            if (!token.IsCancellationRequested)
153→                LogMessage?.Invoke($"수신 오류: {ex.Message}");
154→        }
155→
156→        if (_isConnected)
157→        {
158→            _isConnected = false;
159→            ConnectionChanged?.Invoke(false, "연결 종료");
160→        }
161→    }
162→
163→    /// <summary>
164→    /// 버퍼에서 완성된 TMSVR 패킷 추출 및 처리
165→    /// 패킷 포맷: $TMSVR,length,mode,transaction_id,JSON_data,*XX\r\n
166→    /// </summary>
167→    private void ProcessBuffer()
168→    {
169→        var buf = _recvBuffer.ToString();
170→
171→        while (true)
172→        {
173→            // $TMSVR 헤더 찾기
174→            int headerIdx = buf.IndexOf("$TMSVR", StringComparison.Ordinal);
175→            if (headerIdx < 0)
176→            {
177→                _recvBuffer.Clear();
178→                return;
179→            }
180→
181→            // 헤더 앞의 쓰레기 데이터 제거
182→            if (headerIdx > 0)
183→                buf = buf[headerIdx..];
184→
185→            // 패킷 끝 찾기: ,*XX 패턴 (쉼표 + 별표 + HEX 2자리)
186→            int endIdx = FindPacketEnd(buf);
187→            if (endIdx < 0)
188→                break; // 아직 패킷 미완성
189→
190→            var packet = buf[..endIdx];
191→            buf = buf[endIdx..];
192→            ParseTmsvrPacket(packet);
193→        }
194→
195→        // 남은 데이터를 버퍼에 보존
196→        _recvBuffer.Clear();
197→        _recvBuffer.Append(buf);
198→    }
199→
200→    /// <summary>
201→    /// ,*XX (체크섬) 패턴을 찾아 패킷 끝 인덱스 반환.
202→    /// JSON 내부의 * 문자와 혼동 방지: ,*[0-9A-Fa-f]{2} 뒤에 \r\n 또는 $ 또는 끝이 오는지 확인.
203→    /// </summary>
204→    private static int FindPacketEnd(string buf)
205→    {
206→        int searchFrom = 6; // $TMSVR 최소 길이 이후부터
207→        while (searchFrom < buf.Length)
208→        {
209→            int starIdx = buf.IndexOf(",*", searchFrom, StringComparison.Ordinal);
210→            if (starIdx < 0) return -1;
211→
212→            // ,* 뒤에 HEX 2자리가 있는지 확인
213→            if (starIdx + 4 <= buf.Length)
214→            {
215→                char h1 = buf[starIdx + 2];
216→                char h2 = buf[starIdx + 3];
217→                if (IsHexChar(h1) && IsHexChar(h2))
218→                {
219→                    int endIdx = starIdx + 4;
220→                    // \r\n 스킵
221→                    if (endIdx < buf.Length && buf[endIdx] == '\r') endIdx++;
222→                    if (endIdx < buf.Length && buf[endIdx] == '\n') endIdx++;
223→                    return endIdx;
224→                }
225→            }
226→            searchFrom = starIdx + 1;
227→        }
228→        return -1;
229→    }
230→
231→    private static bool IsHexChar(char c) =>
232→        (c >= '0' && c <= '9') || (c >= 'A' && c <= 'F') || (c >= 'a' && c <= 'f');
233→
234→    /// <summary>
235→    /// TMSVR 패킷 파싱
236→    /// 예: $TMSVR,228,0,3,[{"Item":"Joint_Angle","Value":[...]},...],*2E
237→    /// </summary>
238→    private void ParseTmsvrPacket(string packet)
239→    {
240→        try
241→        {
242→            // $TMSVR,length,mode,transaction_id, 이후 JSON 부분 추출
243→            // 쉼표 4개를 건너뛰면 JSON 시작
244→            int commaCount = 0;
245→            int jsonStart = -1;
246→            for (int i = 0; i < packet.Length; i++)
247→            {
248→                if (packet[i] == ',')
249→                {
250→                    commaCount++;
251→                    if (commaCount == 4)
252→                    {
253→                        jsonStart = i + 1;
254→                        break;
255→                    }
256→                }
257→            }
258→
259→            if (jsonStart < 0) return;
260→
261→            // JSON 끝: ,*XX 패턴 찾기 (끝에서 역방향)
262→            int checksumIdx = packet.LastIndexOf(",*", StringComparison.Ordinal);
263→            if (checksumIdx < jsonStart) return;
264→
265→            var jsonStr = packet[jsonStart..checksumIdx];
266→
267→            // JSON 파싱
268→            var items = JsonSerializer.Deserialize<JsonElement[]>(jsonStr);
269→            if (items == null) return;
270→
271→            double[]? jointAngles = null;
272→            double[]? tcpCoord = null;
273→
274→            foreach (var item in items)
275→            {
276→                var itemName = item.GetProperty("Item").GetString();
277→                var value = item.GetProperty("Value");
278→
279→                if (itemName == "Joint_Angle" && value.ValueKind == JsonValueKind.Array)
280→                {
281→                    jointAngles = new double[6];
282→                    for (int i = 0; i < Math.Min(value.GetArrayLength(), 6); i++)
283→                        jointAngles[i] = value[i].GetDouble();
284→                }
285→                else if ((itemName == "Coord_Base_Tool" || itemName == "Coord_Robot_Tool")
286→                         && value.ValueKind == JsonValueKind.Array)
287→                {
288→                    tcpCoord = new double[6];
289→                    for (int i = 0; i < Math.Min(value.GetArrayLength(), 6); i++)
290→                        tcpCoord[i] = value[i].GetDouble();
291→                }
292→            }
293→
294→            if (jointAngles != null)
295→                DataReceived?.Invoke(jointAngles, tcpCoord ?? new double[6]);
296→        }
297→        catch (Exception ex)
298→        {
299→            LogMessage?.Invoke($"패킷 파싱 오류: {ex.Message}");
300→        }
301→    }
302→
303→    #region TMSCT 비상정지
304→
305→    /// <summary>
306→    /// TMSCT(5890)로 Pause 명령 전송 (일시정지, Listen Node 유지)
307→    /// </summary>
308→    public async Task<string> SendPauseAsync()
309→    {
310→        return await SendTmsctScriptAsync("Pause()");
311→    }
312→
313→    /// <summary>
314→    /// TMSCT(5890)로 Resume 명령 전송
315→    /// </summary>
316→    public async Task<string> SendResumeAsync()
317→    {
318→        return await SendTmsctScriptAsync("Resume()");
319→    }
320→
321→    /// <summary>
322→    /// TMSCT(5890)로 Stop 명령 전송 (완전 정지, Listen Node 종료됨 주의)
323→    /// </summary>
324→    public async Task<string> SendStopAsync()
325→    {
326→        return await SendTmsctScriptAsync("StopAndClearBuffer()");
327→    }
328→
329→    /// <summary>
330→    /// TMSCT 포트(5890)에 일회성 연결 → 스크립트 전송 → 응답 수신 → 연결 종료
331→    /// MCP 서버와 포트 충돌 방지를 위해 일회성 연결 사용
332→    /// </summary>
333→    private async Task<string> SendTmsctScriptAsync(string script)
334→    {
335→        TcpClient? sctTcp = null;
336→        try
337→        {
338→            sctTcp = new TcpClient { SendTimeout = 3000, ReceiveTimeout = 3000 };
339→            await sctTcp.ConnectAsync(Host, 5890);
340→
341→            var stream = sctTcp.GetStream();
342→            var id = (++_sctCmdId).ToString("D2");
343→            var packet = BuildTmsctPacket(id, script);
344→
345→            LogMessage?.Invoke($"[TMSCT] 전송: {packet.TrimEnd()}");
346→
347→            var bytes = Encoding.ASCII.GetBytes(packet);
348→            await stream.WriteAsync(bytes);
349→
350→            // 응답 수신 (최대 3초)
351→            var buf = new byte[1024];
352→            var readTask = stream.ReadAsync(buf, 0, buf.Length);
353→            if (await Task.WhenAny(readTask, Task.Delay(3000)) == readTask)
354→            {
355→                int n = readTask.Result;
356→                var response = Encoding.ASCII.GetString(buf, 0, n);
357→                LogMessage?.Invoke($"[TMSCT] 응답: {response.TrimEnd()}");
358→                return response;
359→            }
360→            else
361→            {
362→                LogMessage?.Invoke("[TMSCT] 응답 타임아웃");
363→                return "TIMEOUT";
364→            }
365→        }
366→        catch (Exception ex)
367→        {
368→            LogMessage?.Invoke($"[TMSCT] 오류: {ex.Message}");
369→            return $"ERROR: {ex.Message}";
370→        }
371→        finally
372→        {
373→            try { sctTcp?.Close(); } catch { }
374→        }
375→    }
376→
377→    /// <summary>
378→    /// TMSCT 패킷 생성: $TMSCT,{len},{id},{script},*{checksum}\r\n
379→    /// </summary>
380→    private static string BuildTmsctPacket(string id, string script)
381→    {
382→        var data = $"{id},{script}";
383→        var length = Encoding.ASCII.GetByteCount(data);
384→        var body = $"TMSCT,{length},{data},";
385→        var checksum = CalcChecksum(body);
386→        return $"${body}*{checksum}\r\n";
387→    }
388→
389→    /// <summary>
390→    /// XOR 체크섬 ($ 제외, * 직전까지)
391→    /// </summary>
392→    private static string CalcChecksum(string content)
393→    {
394→        int xor = 0;
395→        foreach (char c in content)
396→            xor ^= c;
397→        return xor.ToString("X2");
398→    }
399→
400→    #endregion
401→
402→    public void Dispose()
403→    {
404→        Disconnect();
405→        GC.SuppressFinalize(this);
406→    }
407→}
408→

