### 패턴 5: sd_bridge.py 명령 직렬화 (핵심 포팅 패턴)
```csharp
// Python: with lock: ...
// C#: SemaphoreSlim 사용
await _commandLock.WaitAsync(ct);
try
{
    // 명령 실행
    await _cb.TightenAsync(DEV_INDEX, force, length, torque);
    var done = await WaitUntilDoneAsync(BUSY_TIMEOUT_SEC, waitStart: true);
    var achieved = await _cb.GetAchievedTorqueAsync(DEV_INDEX);
    var error = await _cb.GetErrorCodeAsync(DEV_INDEX);
    if (!done) return $"ERR:tighten timeout,torque={achieved:F2},error={error}";
    if (error != 0) return $"ERR:tighten error={error},torque={achieved:F2}";
    await WaitRetractAsync();
    return $"OK:tighten torque={achieved:F2}";
}
finally
{
    _commandLock.Release();
}
```

